    "IntrospectionType", input_value_introspection["type"]
)
type_ = get_type(type_introspection)
if not is_input_type(type_):
    msg = (
        "Introspection must provide input type for input fields,"
        f" but received: {inspect(type_)}."
    )
    raise TypeError(msg)

