                )

def __str__(self) -> str:
        # Lazy import to avoid a cyclic dependency between error and language
        from ..language.print_location import print_location, print_source_location

        output = [self.message]

        if self.nodes:
            output.extend(print_location(node.loc) for node in self.nodes if node.loc)
        elif self.source and self.locations:
            source = self.source
            output.extend(
                print_source_location(source, location) for location in self.locations
            )

        return "\n\n".join(output)

async def _wrapper(
            self: _AsusWrtBridgeT,
        ) -> dict[str, float | str | None] | dict[str, float]:
            try:
                data = await func(self)
            except exceptions as exc:
                raise UpdateFailed(exc) from exc

            if keys is None:
                if not isinstance(data, dict):
                    raise UpdateFailed("Received invalid data type")
                return data

            if isinstance(data, dict):
                return dict(zip(keys, list(data.values()), strict=False))
            return dict(zip(keys, data, strict=False))

